INSERT INTO `content_short_videos` VALUES ('1', '2026-05-18 11:14:34.504', '2026-05-20 12:15:01.644', null, '1', '模仿小红书的短视频风格，生成一个10s的默默小狗脑袋；小狗还叫的场景；背景在农家大院里面；阳光温和。', 'sv-1779074074', '', '', '标题：谁懂啊！农家院晒太阳的歪头小狗会撒娇叫?\n摘要：记录农家大院暖阳下歪头哼叫的软萌小狗，看完整个人都被治愈了。\nSEO描述：周末回农村老家，偶遇院子里晒着太阳歪头撒娇叫的软乎乎修勾，谁能拒绝这么治愈的小狗呀！\nSEO关键词：治愈小狗，农家大院，萌宠日常，阳光小狗，农村生活，软萌修勾\n正文：\n0-5s：\n画面：暖阳光斜洒在农家青砖大院，毛茸茸的小狗脑袋从院门口慢慢探进来，歪着黑溜溜的脑袋看向镜头，周身落着阳光碎斑\n旁白（软甜女声）：谁家的乖乖小狗跑出来啦\n字幕：谁家的乖乖修勾呀?\n5-15s：\n画面：镜头推近特写，小狗晃了晃耷拉的耳朵，喉咙发出轻轻的呼噜声，接着小声汪汪叫了两声，尾巴摇得带起风，绒毛在阳光下泛着暖光\n旁白：晒完太阳居然会撒娇叫诶\n字幕：晒完太阳会撒娇谁顶得住啊\n15-30s：\n画面：小狗慢悠悠凑过来，鼻尖蹭了蹭镜头，整个身子露出来站在院中央阳光下摇尾巴，背景是院角的青菜和竹篱笆\n旁白：乡下的快乐，全是小狗给的呀\n字幕：今日份治愈已签收✅', '30', '', 'uploads/file/9074a0b13ab85eb60d4a1ec518d2f891_20260520121231.png,uploads/file/9074a0b13ab85eb60d4a1ec518d2f891_20260520121231.png', '', 'failed', 'DashScope 提交任务 HTTP 400: {\"request_id\":\"9c26d8fe-f218-9c16-94dc-9b63bd2661db\",\"code\":\"InvalidParameter.DataInspection\",\"message\":\"The media format is not supported or incorrect for the data inspection.\"}', 'volc', '', null, '0', '0', 'uploads/file/9074a0b13ab85eb60d4a1ec518d2f891_20260520121231.png', 'uploads/file/9074a0b13ab85eb60d4a1ec518d2f891_20260520121231.png');
