INSERT INTO `sys_error` VALUES ('1', '2026-04-28 22:16:31.905', '2026-04-28 22:16:31.905', null, '后端', '适配数据库失败请检查casbin表是否为InnoDB引擎! | 错误: Error 1071 (42000): Specified key was too long; max key length is 1000 bytes \n 源文件:D:/golang/gin-vue-admin/server/utils/casbin_util.go:23 \n 调用栈：github.com/flipped-aurora/gin-vue-admin/server/utils.GetCasbin.func1\n	D:/golang/gin-vue-admin/server/utils/casbin_util.go:23\nsync.(*Once).doSlow\n	D:/golang/exe/src/sync/once.go:76\nsync.(*Once).Do\n	D:/golang/exe/src/sync/once.go:67\ngithub.com/flipped-aurora/gin-vue-admin/server/utils.GetCasbin\n	D:/golang/gin-vue-admin/server/utils/casbin_util.go:20\ngithub.com/flipped-aurora/gin-vue-admin/server/initialize.Routers.CasbinHandler.func4\n	D:/golang/gin-vue-admin/server/middleware/casbin_rbac.go:23\ngithub.com/gin-gonic/gin.(*Context).Next\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/flipped-aurora/gin-vue-admin/server/initialize.Routers.JWTAuth.func3\n	D:/golang/gin-vue-admin/server/middleware/jwt.go:69\ngithub.com/gin-gonic/gin.(*Context).Next\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.LoggerWithConfig.func1\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/logger.go:249\ngithub.com/gin-gonic/gin.(*Context).Next\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/flipped-aurora/gin-vue-admin/server/initialize.Routers.GinRecovery.func2\n	D:/golang/gin-vue-admin/server/middleware/error.go:78\ngithub.com/gin-gonic/gin.(*Context).Next\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.(*Engine).handleHTTPRequest\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:633\ngithub.com/gin-gonic/gin.(*Engine).ServeHTTP\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:589\nnet/http.serverHandler.ServeHTTP\n	D:/golang/exe/src/net/http/server.go:3210\nnet/http.(*conn).serve\n	D:/golang/exe/src/net/http/server.go:2092 \n 最终调用方法:D:/golang/gin-vue-admin/server/utils/casbin_util.go:23 (GetCasbin lines 19-52)\n----- 产生日志的方法代码如下 -----\nfunc GetCasbin() *casbin.SyncedCachedEnforcer {\r\n	once.Do(func() {\r\n		a, err := gormadapter.NewAdapterByDB(global.GVA_DB)\r\n		if err != nil {\r\n			zap.L().Error(\"适配数据库失败请检查casbin表是否为InnoDB引擎!\", zap.Error(err))\r\n			return\r\n		}\r\n		text := `\r\n		[request_definition]\r\n		r = sub, obj, act\r\n		\r\n		[policy_definition]\r\n		p = sub, obj, act\r\n		\r\n		[role_definition]\r\n		g = _, _\r\n		\r\n		[policy_effect]\r\n		e = some(where (p.eft == allow))\r\n		\r\n		[matchers]\r\n		m = r.sub == p.sub && keyMatch2(r.obj,p.obj) && r.act == p.act\r\n		`\r\n		m, err := model.NewModelFromString(text)\r\n		if err != nil {\r\n			zap.L().Error(\"字符串加载模型失败!\", zap.Error(err))\r\n			return\r\n		}\r\n		syncedCachedEnforcer, _ = casbin.NewSyncedCachedEnforcer(m, a)\r\n		syncedCachedEnforcer.SetExpireTime(60 * 60)\r\n		_ = syncedCachedEnforcer.LoadPolicy()\r\n	})\r\n	return syncedCachedEnforcer\r\n}', 'error', null, '未处理');
