INSERT INTO `sys_error` VALUES ('174', '2026-05-12 19:18:42.552', '2026-05-12 19:18:42.552', null, '后端', '获取公开文章失败! | 错误: invalid connection \n 源文件:D:/golang/gin-vue-admin/server/api/v1/content/content_article.go:293 \n 调用栈：github.com/flipped-aurora/gin-vue-admin/server/api/v1/content.(*ArticleApi).GetPublishedBySlug\n	D:/golang/gin-vue-admin/server/api/v1/content/content_article.go:293\ngithub.com/gin-gonic/gin.(*Context).Next\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.LoggerWithConfig.func1\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/logger.go:249\ngithub.com/gin-gonic/gin.(*Context).Next\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/flipped-aurora/gin-vue-admin/server/initialize.Routers.GinRecovery.func2\n	D:/golang/gin-vue-admin/server/middleware/error.go:78\ngithub.com/gin-gonic/gin.(*Context).Next\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/context.go:185\ngithub.com/gin-gonic/gin.(*Engine).handleHTTPRequest\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:633\ngithub.com/gin-gonic/gin.(*Engine).ServeHTTP\n	C:/Users/admin/go/pkg/mod/github.com/gin-gonic/gin@v1.10.0/gin.go:589\nnet/http.serverHandler.ServeHTTP\n	D:/golang/exe/src/net/http/server.go:3210\nnet/http.(*conn).serve\n	D:/golang/exe/src/net/http/server.go:2092 \n 最终调用方法:D:/golang/gin-vue-admin/server/api/v1/content/content_article.go:293 (GetPublishedBySlug lines 285-299)\n----- 产生日志的方法代码如下 -----\nfunc (a *ArticleApi) GetPublishedBySlug(c *gin.Context) {\r\n	slug := c.Param(\"slug\")\r\n	data, err := articleService.GetPublishedBySlug(slug)\r\n	if err != nil {\r\n		if errors.Is(err, gorm.ErrRecordNotFound) {\r\n			response.FailWithMessage(\"文章不存在或未发布\", c)\r\n			return\r\n		}\r\n		global.GVA_LOG.Error(\"获取公开文章失败!\", zap.Error(err))\r\n		response.FailWithMessage(\"获取失败\", c)\r\n		return\r\n	}\r\n	_ = articleService.IncViewBySlug(slug)\r\n	response.OkWithDetailed(data, \"获取成功\", c)\r\n}', 'error', null, '未处理');
